'use strict';
// KayKit Adventurers + Skeletons (CC0, Kay Lousberg) pre-rendered via three.js.
// Sheets: 8 cols x 96px frames, row 0 = BACK view run cycle, row 1 = FRONT view.
const SPRITE_FRAME = 96, SPRITE_FRAMES = 8, SPRITE_ROW_BACK = 0, SPRITE_ROW_FRONT = 1;
const SPRITE_DATA = {
  chars: {
    knight: 'data:image/png;base64,',
    barbarian: 'data:image/png;base64,',
    rogue: 'data:image/png;base64,',
    mage: 'data:image/png;base64,',
    hooded: 'data:image/png;base64,',
  },
  bosses: {
    bonewarrior: 'data:image/png;base64,',
    necromancer: 'data:image/png;base64,',
    bonescout: 'data:image/png;base64,',
    bonefiend: 'data:image/png;base64,',
  },
};

// Loader: create Image objects for all sprites
const SPRITES = {};
for (const group of ['chars', 'bosses']) {
  for (const key in SPRITE_DATA[group]) {
    const img = new Image();
    img.src = SPRITE_DATA[group][key];
    SPRITES[group + '.' + key] = img;
  }
}

function spriteReady(img) {
  return img && img.complete && img.naturalWidth > 0;
}

// Tint cache: create tinted versions of sprite sheets
const tintCache = new Map();
function tintedSheet(img, color) {
  const cacheKey = img.src.slice(-40) + color;
  if (tintCache.has(cacheKey)) return tintCache.get(cacheKey);
  
  const canvas = document.createElement('canvas');
  canvas.width = img.naturalWidth;
  canvas.height = img.naturalHeight;
  const ctx = canvas.getContext('2d');
  
  ctx.drawImage(img, 0, 0);
  ctx.globalCompositeOperation = 'source-atop';
  ctx.globalAlpha = 0.38;
  ctx.fillStyle = color;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  
  tintCache.set(cacheKey, canvas);
  return canvas;
}
